require "config.ItemConfig"

local JobList = MemoryPool.newTable()

JobStatus = {
    HAVE = 1, --Have a state
    NO_HAVE = 2 --Unowned state
}

--Current career choice
CurSelectJob = {
    Have_Select_Job = 3,
    No_Select_Job = 4,
}

JobConfig = {}

function JobConfig.LoadConfig()
    local configs = FileUtil.getConfigFromCsv("setting/JobConfig.csv", 3)
    for _, config in pairs(configs) do
        local status1 = 0
        if tonumber(config.type) == 1 or tonumber(config.type) == 0 then
            status1 = JobStatus.HAVE
        else
            status1 = JobStatus.NO_HAVE
        end
        table.insert(JobList, {
            id = tonumber(config.id),
            name = config.name,
            describe = config.describe,
            icon = config.icon,
            image = config.image,
            quality = config.quality,
            type = tonumber(config.type),
            sort = tonumber(config.sort),
            goods = config.initializeItem,
            status = status1,
            isOpen = false,
            times = 0,
            select = CurSelectJob.No_Select_Job
        })
    end
    table.sort(JobList, function(a, b)

        if a.status ~= b.status then
            return a.status < b.status
        end

        if a.sort ~= b.sort then
            return a.sort > b.sort
        end
        return a.id < b.id
    end)
end

function JobConfig.getGoodsIdByJobId(id)
    for _, item in pairs(JobList) do
        if item.id == id then
            local goods = {}
            local ids = StringUtil.split(item.goods, "#")
            for _, id in pairs(ids) do
                local result = ItemConfig:getItemIdById(tonumber(id))
                table.insert(goods, result)
            end
            return goods
        end
    end
end


--Update class status
function JobConfig.updateStatus(id, time)
    for _, item in pairs(JobList) do

        --A chosen occupation
        if item.id == GUIJobChoice.cur_select_id then
            item.select = CurSelectJob.Have_Select_Job
        else
            item.select = CurSelectJob.No_Select_Job
        end

        if item.id == id then
            item.times = time
            if item.times > 0 then
                item.status = JobStatus.HAVE
            else
                item.status = JobStatus.NO_HAVE
            end
            break
        end
    end

    table.sort(JobList, function(a, b)

        if a.type ~= b.type then
            return a.type < b.type
        end

        if a.select ~= b.select then
            return a.select < b.select
        end

        if a.status ~= b.status then
            return a.status < b.status
        end

        if a.sort ~= b.sort then
            return a.sort > b.sort
        end
        return a.id < b.id
    end)
end

function JobConfig.getJobList()
    return JobList
end

function JobConfig.getJobById(id)
    for _, job in pairs(JobList) do
        if job.id == id then
            return job
        end
    end
    return nil
end

function JobConfig.changeJobIsOpen(id, bool)
    for _, job in pairs(JobList) do
        if job.id == id then
            job.isOpen = bool
            return job
        end
    end
end

function JobConfig.getDefaultJob()
    for i, item in pairs(JobList) do
        if item.type == Define.JobType.DefaultJob then
            return item
        end
    end
end